#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int calculate_CA(int *A, int n, int i) {
    int CA = 0;
    for (int j = 0; j < n; j++) {
        if (A[j] < A[i]) {
            CA++;
        }
    }
    return CA;
}

int calculate_CB(int *B, int n, int i) {
    int CB = 0;
    for (int j = 0; j < n; j++) {
        if (B[j] < B[i]) {
            CB++;
        }
    }
    return CB;
}

int calculate_F(int *P1, int *P2, int n) {
    int result = 0;
    for (int i = 0; i < n; i++) {
        if (P1[i] == P2[i]) {
            result++;
        }
    }
    return result % MOD;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n, E;
        scanf("%d %d", &n, &E);
        int *A = (int*)malloc(n * sizeof(int));
        int *B = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &B[i]);
        }
        int *P1 = (int*)malloc(n * sizeof(int));
        int *P2 = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            P1[i] = calculate_CA(A, n, i);
            P2[i] = calculate_CB(B, n, i);
        }
        printf("%d\n", calculate_F(P1, P2, n));
        free(A);
        free(B);
        free(P1);
        free(P2);
    }
    return 0;
}

