        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int E = scanner.nextInt();
            int[] A = new int[n];
            int[] B = new int[n];
            for (int i = 0; i < n; i++) {
                A[i] = scanner.nextInt();
            }
            for (int i = 0; i < n; i++) {
                B[i] = scanner.nextInt();
            }
            int[] P1 = new int[n];
            int[] P2 = new int[n];
            for (int i = 0; i < n; i++) {
                P1[i] = calculate_CA(A, n, i);
                P2[i] = calculate_CB(B, n, i);
            }
            System.out.println(calculate_F(P1, P2, n));
        }
    }
    public static int calculate_CA(int[] A, int n, int i) {
        int CA = 0;
        for (int j = 0; j < n; j++) {
            if (A[j] < A[i]) {
                CA++;
            }
        }
        return CA;
    }
    public static int calculate_CB(int[] B, int n, int i) {
        int CB = 0;
        for (int j = 0; j < n; j++) {
            if (B[j] < B[i]) {
                CB++;
            }
        }
        return CB;
    }
    public static int calculate_F(int[] P1, int[] P2, int n) {
        int result = 0;
        for (int i = 0; i < n; i++) {
            if (P1[i] == P2[i]) {
                result++;
            }
        }
        return result % MOD;
    }
}

